css: body {
  background-color: #f2f2f2;
}
#confetti-container {
  position: relative;
  width: 100%;
  height: 100vh;
}
#button {
  position: absolute;
  top: 50%;
  left: 50%;
  transform: translate(-50%, -50%);
}
.confetti-piece {
  position: absolute;
  width: 20px;
  height: 20px;
  background-color: #ff69b4;
  border-radius: 50%;
  animation: fall 2s infinite;
}
#happy-birthday-message {
  position: absolute;
  top: 50%;
  left: 50%;
  transform: translate(-50%, -50%);
  font-size: 30px;
  font-weight: bold;
}
@keyframes fall {
  0% {
    top: 0;
  }
  100% {
    top: 100vh;
  }
}

js: const button = document.getElementById('button');
const confettiContainer = document.getElementById('confetti-container');
const happyBirthdayMessage = document.getElementById('happy-birthday-message');

button.addEventListener('click', () => {
  generateConfetti();
  showHappyBirthdayMessage();
});

function generateConfetti() {
  confettiContainer.innerHTML = '';
  for (let i = 0; i < 100; i++) {
    const confettiPiece = document.createElement('div');
    confettiPiece.classList.add('confetti-piece');
    const randomX = Math.random() * window.innerWidth;
    const randomY = -20;
    confettiPiece.style.top = `${randomY}px`;
    confettiPiece.style.left = `${randomX}px`;
    confettiContainer.appendChild(confettiPiece);
  }
}

function showHappyBirthdayMessage() {
  happyBirthdayMessage.textContent = 'Happy Birthday!';
  happyBirthdayMessage.style.opacity = 1;
  setTimeout(() => {
    happyBirthdayMessage.style.opacity = 0;
  }, 5000);
}
